13	// ServiceStats tracks transfer statistics for a single service.
14	type ServiceStats struct {
15		Name          string `json:"name"`
16		Requests      int    `json:"requests"`
17		RequestBytes  int64  `json:"requestBytes"`
18		ResponseBytes int64  `json:"responseBytes"`
19		Wants         int    `json:"wants"`
20		Haves         int    `json:"haves"`
21		Commands      int    `json:"commands"`
22	}
