73	// countingRoundTripper wraps an HTTP transport to record transfer stats.
74	type countingRoundTripper struct {
75		base  http.RoundTripper
76		label string
77		stats *statsCollector
78	}
79	
80	func (rt *countingRoundTripper) RoundTrip(req *http.Request) (*http.Response, error) {
81		res, err := rt.base.RoundTrip(req)
82		if err != nil {
83			return nil, fmt.Errorf("round trip: %w", err)
84		}
85	
86		serviceName := req.Header.Get(gitproto.StatsPhaseHeader)
87		if serviceName == "" {
88			serviceName = req.URL.Query().Get("service")
89			if serviceName == "" {
90				serviceName = strings.TrimPrefix(req.URL.Path[strings.LastIndex(req.URL.Path, "/")+1:], "/")
91			}
92		}
93		name := strings.TrimSpace(rt.label + " " + serviceName)
94		requestBytes := req.ContentLength
95		if requestBytes < 0 {
96			requestBytes = 0
97		}
98	
99		res.Body = &countingReadCloser{
100			ReadCloser: res.Body,
101			onClose: func(n int64) {
102				rt.stats.recordRoundTrip(name, requestBytes, n)
103			},
104		}
105		return res, nil
106	}
