295	func newConn(raw Endpoint, label string, stats *statsCollector, httpClient *http.Client) (*gitproto.Conn, error) {
296		ep, err := transport.ParseURL(raw.URL)
297		if err != nil {
298			return nil, fmt.Errorf("parse endpoint: %w", err)
299		}
300		authEp := auth.Endpoint{
301			Username:      raw.Username,
302			Token:         raw.Token,
303			BearerToken:   raw.BearerToken,
304			SkipTLSVerify: raw.SkipTLSVerify,
305		}
306		authMethod, err := auth.Resolve(authEp, ep)
307		if err != nil {
308			return nil, fmt.Errorf("resolve auth: %w", err)
309		}
310		client := instrumentHTTPClient(httpClient, raw.SkipTLSVerify, label, stats)
311		conn := gitproto.NewConnWithHTTPClient(ep, label, authMethod, client)
312		conn.FollowInfoRefsRedirect = raw.FollowInfoRefsRedirect
313		return conn, nil
314	}
315	
316	func instrumentHTTPClient(base *http.Client, skipTLS bool, label string, stats *statsCollector) *http.Client {
317		if base == nil {
318			base = &http.Client{Transport: gitproto.NewHTTPTransport(skipTLS)}
319		}
320		clone := *base
321		baseRT := clone.Transport
322		if baseRT == nil {
323			baseRT = gitproto.NewHTTPTransport(skipTLS)
324		}
325		clone.Transport = &countingRoundTripper{base: baseRT, label: label, stats: stats}
326		return &clone
327	}
