35	// Stats holds the collected transfer statistics.
36	type Stats struct {
37		Enabled      bool                     `json:"enabled"`
38		Items        map[string]*ServiceStats `json:"items"`
39		Sides        []SideBytes              `json:"sides,omitempty"`
