51	// statsCollector is a concurrency-safe stats collector.
52	type statsCollector struct {
53		enabled   bool
54		startedAt time.Time
55		mu        sync.Mutex
56		items     map[string]*ServiceStats
57		sidesMu   sync.RWMutex
58		sides     map[string]*sideCounter
59	}
60	
61	func newStats(enabled bool) *statsCollector {
62		return &statsCollector{
63			enabled:   enabled,
64			startedAt: time.Now(),
65			items:     map[string]*ServiceStats{},
66			sides:     map[string]*sideCounter{},
67		}
68	}
69	
70	func (s *statsCollector) ensure(name string) *ServiceStats {
71		item, ok := s.items[name]
72		if !ok {
73			item = &ServiceStats{Name: name}
74			s.items[name] = item
75		}
76		return item
77	}
