	t.Parallel()
	stats := newStats(true)
	stats.setSideDisplay("source", "github.com")
	stats.setSideDisplay("target", "example.test")
	stats.side("source").bytes.Store(2 * 1024 * 1024)
	stats.side("target").bytes.Store(1024 * 1024)

